module DefaultClusterParameters =
  struct
    type nonrec t =
      {
      parameterGroupFamily: String_.t option
        [@ocaml.doc
          "The name of the cluster parameter group family to which the engine default parameters apply."];
      marker: String_.t option
        [@ocaml.doc
          "A value that indicates the starting point for the next set of response records in a subsequent request. If a value is returned in a response, you can retrieve the next set of records by providing this returned marker value in the Marker parameter and retrying the command. If the Marker field is empty, all response records have been retrieved for the request."];
      parameters: ParametersList.t option
        [@ocaml.doc "The list of cluster default parameters."]}
    let make ?parameterGroupFamily =
      fun ?marker ->
        fun ?parameters ->
          fun () -> { parameterGroupFamily; marker; parameters }
    let to_value x =
      structure_to_value
        [("ParameterGroupFamily",
           (Option.map x.parameterGroupFamily ~f:String_.to_value));
        ("Marker", (Option.map x.marker ~f:String_.to_value));
        ("Parameters", (Option.map x.parameters ~f:ParametersList.to_value))]
    let to_query v = to_query to_value v
    let of_xml xml_arg0 =
      let parameters =
        (Option.map ~f:ParametersList.of_xml)
          (Xml.child xml_arg0 "Parameters") in
      let marker =
        (Option.map ~f:String_.of_xml) (Xml.child xml_arg0 "Marker") in
      let parameterGroupFamily =
        (Option.map ~f:String_.of_xml)
          (Xml.child xml_arg0 "ParameterGroupFamily") in
      make ?parameters ?marker ?parameterGroupFamily ()
    let of_string s = of_xml (Awso.Xml.parse_response s)[@@warning "-32"]
    let of_json json__ =
      let parameters = field_map json__ "Parameters" ParametersList.of_json in
      let marker = field_map json__ "Marker" String_.of_json in
      let parameterGroupFamily =
        field_map json__ "ParameterGroupFamily" String_.of_json in
      make ?parameters ?marker ?parameterGroupFamily ()
    let to_json v = composed_to_json to_value v
  end[@@ocaml.doc
       "Describes the default cluster parameters for a parameter group family."]
