      marker: String_.t option
        [@ocaml.doc
          "A value that indicates the starting point for the next set of response records in a subsequent request. If a value is returned in a response, you can retrieve the next set of records by providing this returned marker value in the Marker parameter and retrying the command. If the Marker field is empty, all response records have been retrieved for the request."]}
    and responseMetaData = unit
    and t =
      {
      describeUsageLimitsResult: describeUsageLimitsResult ;
      responseMetaData: responseMetaData }
    type error =
      [ `ClusterNotFoundFault of ClusterNotFoundFault.t 
      | `UnsupportedOperationFault of UnsupportedOperationFault.t 
      | `Unknown_operation_error of (string * string option) ]
    let context_ = "UsageLimitList"
    let make ?usageLimits =
      fun ?marker ->
        fun () ->
          {
            describeUsageLimitsResult = { usageLimits; marker };
            responseMetaData = ()
          }
    let error_of_json name json =
      match name with
      | "ClusterNotFoundFault" ->
          `ClusterNotFoundFault (ClusterNotFoundFault.of_json json)
      | "UnsupportedOperationFault" ->
          `UnsupportedOperationFault (UnsupportedOperationFault.of_json json)
      | name ->
          `Unknown_operation_error
            (name, (Some (Yojson.Safe.to_string json)))
    let error_of_xml name xml =
      match name with
      | "ClusterNotFoundFault" ->
          `ClusterNotFoundFault (ClusterNotFoundFault.of_xml xml)
      | "UnsupportedOperationFault" ->
          `UnsupportedOperationFault (UnsupportedOperationFault.of_xml xml)
      | name ->
          `Unknown_operation_error (name, (Some (Awso.Xml.to_string xml)))
    let error_to_json : error -> Yojson.Safe.t =
      function
      | `ClusterNotFoundFault e ->
          `Assoc
            [("error", (`String "ClusterNotFoundFault"));
            ("details", (ClusterNotFoundFault.to_json e))]
      | `UnsupportedOperationFault e ->
          `Assoc
            [("error", (`String "UnsupportedOperationFault"));
            ("details", (UnsupportedOperationFault.to_json e))]
      | `Unknown_operation_error (code, msg) ->
          `Assoc (("error", (`String code)) ::
            ((match msg with
              | None -> []
              | Some m -> [("message", (`String m))])))
    let to_value t =
      let x = t.describeUsageLimitsResult in
      structure_to_wrapped_value
        [("UsageLimits", (Option.map x.usageLimits ~f:UsageLimits.to_value));
        ("Marker", (Option.map x.marker ~f:String_.to_value))]
        ~wrapper:"DescribeUsageLimitsResult" ~response:"ResponseMetaData"
    let to_query v = to_query to_value v
    let of_xml t =
      let xml_arg0 =
        Xml.child_exn ~context:context_ t "DescribeUsageLimitsResult" in
      let marker =
        (Option.map ~f:String_.of_xml) (Xml.child xml_arg0 "Marker") in
      let usageLimits =
        (Option.map ~f:UsageLimits.of_xml) (Xml.child xml_arg0 "UsageLimits") in
      make ?marker ?usageLimits ()
    let of_string s = of_xml (Awso.Xml.parse_response s)[@@warning "-32"]
    let of_json json__ =
      let marker = field_map json__ "Marker" String_.of_json in
      let usageLimits = field_map json__ "UsageLimits" UsageLimits.of_json in
      make ?marker ?usageLimits ()
    let to_json v = composed_to_json to_value v
  end[@@ocaml.doc
       "Shows usage limits on a cluster. Results are filtered based on the combination of input usage limit identifier, cluster identifier, and feature type parameters: If usage limit identifier, cluster identifier, and feature type are not provided, then all usage limit objects for the current account in the current region are returned. If usage limit identifier is provided, then the corresponding usage limit object is returned. If cluster identifier is provided, then all usage limit objects for the specified cluster are returned. If cluster identifier and feature type are provided, then all usage limit objects for the combination of cluster and feature are returned."]
